    """
    Convert a non-negative integer to its binary representation as a string.
    """
    if n == 0:
        return "0"

    binary_digits = []
    while n > 0:
        remainder = n % 2
        binary_digits.append(str(remainder))
        n //= 2

    # Reverse the digits to get the correct binary representation
    return ''.join(reversed(binary_digits))

