def search(arr):
    if not arr:
        return None
    left, right = 0, len(arr) - 1
    while left < right:
        mid = (left + right) // 2
        # Check if mid is the odd one out
        # If mid is odd, compare with mid-1
        # If mid is even, compare with mid+1
        if arr[mid] != arr[mid - 1] and arr[mid] != arr[mid + 1]:
            return arr[mid]
        # If the left element is different, the odd one is on the left
        elif arr[mid] == arr[mid + 1]:
            right = mid
        else:
            left = mid + 1
    return arr[left]
