def sum_common_divisors(a, b):
    """
    Returns the sum of all common divisors of two numbers a and b.
    """
    if a == 0 and b == 0:
        return 0  # Convention for 0,0
    if a == 0 or b == 0:
        return 0  # No common divisors for 0 and a non-zero number

    # Ensure a is the smaller number to iterate up to sqrt(min(a,b))
    if a > b:
        a, b = b, a

    common_divisors = []

    # Iterate up to the smaller number
    for i in range(1, a + 1):
        if a % i == 0 and b % i == 0:
            common_divisors.append(i)

    return sum(common_divisors)
