def find_solution(a, b, n):
    # Special case: if either a or b is zero
    if a == 0 and b == 0:
        return None
    if a == 0:
        if n % b == 0:
            return (0, n // b)
        else:
            return None
    if b == 0:
        if n % a == 0:
            return (n // a, 0)
        else:
            return None

    # Extended Euclidean Algorithm to find x and y such that ax + by = gcd(a, b)
    def extended_gcd(a, b):
        if b == 0:
            return (1, 0, a)
        else:
            x1, y1, g = extended_gcd(b, a % b)
            return (y1, x1 - (a // b) * y1, g)

    # Find gcd and initial solution
    x1, y1, g = extended_gcd(a, b)

    # Check if solution exists
    if n % g != 0:
        return None

    # Scale the solution
    x = x1 * (n // g)
    y = y1 * (n // g)

    return (x, y)
