import math

def find_solution(a, b, n):
    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)
    if a == 0:
        return None if n % b != 0 else (0, n // b)
    if b == 0:
        return None if n % a != 0 else (n // a, 0)

    gcd = math.gcd(a, b)
    if n % gcd != 0:
        return None

    a_div, b_div = a // gcd, b // gcd
    n_div = n // gcd

    # Extended Euclidean Algorithm to find x and y such that a_div*x + b_div*y = 1
    def extended_gcd(a, b):
        if b == 0:
            return (1, 0)
        x, y = extended_gcd(b, a % b)
        return (y, x - (a // b) * y)

    x0, y0 = extended_gcd(a_div, b_div)
    # Particular solution
    x = x0 * n_div
    y = y0 * n_div

    # General solution: x = x0 + (b/gcd)*t, y = y0 - (a/gcd)*t
    # We want to find a solution where x and y are integers (they always are for integer t)
    # To get a specific solution, we can adjust t to make x and y as small as possible.
    # Let's find t such that x is in the range [0, b_div)
    t = -x // b_div
    x += t * b_div
    y -= t * a_div

    return (x, y)
