    left, right = 0, n - 1
    first_occurrence = -1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == element:
            first_occurrence = mid
            right = mid - 1  # Search left half for the first occurrence
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    # If element not found, return False
    if first_occurrence == -1:
        return False

    # Calculate the last occurrence index using binary search
    left, right = first_occurrence, n - 1
    last_occurrence = first_occurrence
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == element:
            last_occurrence = mid
            left = mid + 1  # Search right half for the last occurrence
        else:
            right = mid - 1

    # Calculate the frequency
    frequency = last_occurrence - first_occurrence + 1

    # Check if frequency is more than n/2
    return frequency > n // 2

