def get_total_number_of_sequences(m, n):
    # Initialize dp table with 0s. dp[i][j] represents the number of sequences
    # of length i ending with the number j.
    dp = [[0] * (m + 1) for _ in range(n + 1)]

    # Base case: sequences of length 1. Any number from 1 to m is valid.
    for j in range(1, m + 1):
        dp[1][j] = 1

    # Fill the dp table for sequences of length 2 to n.
    for i in range(2, n + 1):
        for j in range(1, m + 1):
            # The previous element k must be in the range [ceil(j/2), j-1].
            # We iterate through all possible values of k.
            for k in range(1, j):
                if k * 2 <= j:
                    dp[i][j] += dp[i - 1][k]

    # Sum up all sequences of length n.
    total = sum(dp[n])
    return total
