def max_sum_bitonic(arr):
    n = len(arr)
    if n == 0:
        return 0

    # LIS[i] will store the length of the longest increasing subsequence ending at index i
    LIS = [1] * n
    # LDS[i] will store the length of the longest decreasing subsequence starting at index i
    LDS = [1] * n

    # Calculate LIS for all indices
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j]:
                LIS[i] = max(LIS[i], LIS[j] + 1)

    # Calculate LDS for all indices
    for i in range(n - 2, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[i] > arr[j]:
                LDS[i] = max(LDS[i], LDS[j] + 1)

    # Find the maximum sum of a bitonic subsequence
