def newman_prime(n: int) -> int:
    """
    Returns the nth Newman-Shanks-Williams (NSW) prime number.
    """
    # NSW numbers are defined by the recurrence:
    # P(0) = 1, P(1) = 1, P(2) = 7
    # P(n) = 6 * P(n-1) - P(n-2) - P(n-3)

    if n == 1:
        return 1
    if n == 2:
        return 1
    if n == 3:
        return 7

    # Generate NSW numbers until we find the nth prime
    p0, p1, p2 = 1, 1, 7
    count = 3  # We have found 3 primes so far (1, 1, 7)

    while True:
        p3 = 6 * p2 - p1 - p0
        count += 1

        # Check if p3 is prime
        if is_prime(p3):
            if count == n:
                return p3
        # Update the sequence
        p0, p1, p2 = p1, p2, p3

