def group_tuples(tuples):
    if not tuples:
        return []

    # Group elements by their first element
    grouped = {}
    for tup in tuples:
        key = tup[0]
        if key not in grouped:
            grouped[key] = []
        grouped[key].append(tup)

    # Create the result list
    result = []
    for key, items in grouped.items():
        if len(items) == 1:
            result.append(items[0])
        else:
            # Create a new tuple with the first element and all second elements
            combined = (key,) + tuple(item[1] for item in items)
            result.append(combined)

    return result
